## Implementation guide

### Step 1: Add Claude invoke wrappers to `gui/src/bridge.ts`

Add after the existing command wrappers (around line 108):

```typescript
// ── Claude sidecar commands ──────────────────────────────────────

/** Send a message to Claude via the sidecar. Returns the generated message ID. */
export async function claudeSendMessage(
  text: string,
  context?: { selectedEntity?: string; diagnostics?: string[]; constraints?: string[] },
): Promise<string> {
  // The Tauri command uses snake_case field names
  const ctx = context ? {
    selected_entity: context.selectedEntity,
    diagnostics: context.diagnostics,
    constraints: context.constraints,
  } : undefined;
  return invoke<string>('claude_send_message', { text, context: ctx });
}

/** Abort the current Claude generation. */
export async function claudeAbort(): Promise<void> {
  return invoke('claude_abort');
}

/** Clear the Claude conversation session. */
export async function claudeClearSession(): Promise<void> {
  return invoke('claude_clear_session');
}
```

### Step 2: Add Claude event listeners to `gui/src/bridge.ts`

Add after the existing event listeners:

```typescript
// ── Claude event listeners ───────────────────────────────────────

import type { OutboundMessage } from '../sidecar/src/types';

/** Subscribe to all Claude sidecar events. Returns a single unlisten function. */
export async function subscribeToClaudeEvents(
  handler: (msg: OutboundMessage) => void,
): Promise<UnlistenFn> {
  const unlisteners = await Promise.all([
    listen<{ id: string; content: string }>('claude-text-delta', (e) =>
      handler({ type: 'text_delta', id: e.payload.id, content: e.payload.content })),
    listen<{ id: string; content: string }>('claude-thinking-delta', (e) =>
      handler({ type: 'thinking_delta', id: e.payload.id, content: e.payload.content })),
    listen<{ id: string; tool_name: string; tool_input: Record<string, unknown> }>('claude-tool-call', (e) =>
      handler({ type: 'tool_call', id: e.payload.id, tool_name: e.payload.tool_name, tool_input: e.payload.tool_input })),
    listen<{ id: string; tool_name: string; result: unknown }>('claude-tool-result', (e) =>
      handler({ type: 'tool_result', id: e.payload.id, tool_name: e.payload.tool_name, result: e.payload.result })),
    listen<{ id: string }>('claude-done', (e) =>
      handler({ type: 'done', id: e.payload.id })),
    listen<{ id: string; message: string }>('claude-error', (e) =>
      handler({ type: 'error', id: e.payload.id, message: e.payload.message })),
    listen<Record<string, never>>('claude-ready', () =>
      handler({ type: 'ready' })),
  ]);
  return () => unlisteners.forEach((u) => u());
}
```

### Step 3: Wire `App.tsx`

Replace the no-op callbacks (lines 60-63) and add event subscription:

```typescript
import {
  // ... existing imports ...
  claudeSendMessage,
  claudeAbort,
  subscribeToClaudeEvents,
} from './bridge';

// In the App component:
const claudeStore = createClaudeStore({
  onSend: (id, text, context) => {
    claudeSendMessage(text, {
      selectedEntity: context.selectedEntity,
      diagnostics: context.diagnostics,
      constraints: context.constraints,
    }).catch((err) => {
      const msg = err instanceof Error ? err.message : String(err);
      claudeStore.addSystemMessage('sidecar', `Failed to send: ${msg}`);
    });
  },
  onAbort: () => {
    claudeAbort().catch((err) => {
      console.error('Claude abort failed:', err);
    });
